async approveRefund(refundId: string, adminNote: string) {
  const refund = await this.refundRepository.findOne({
    where: { id: refundId },
    relations: ['order', 'order.payment']
  });

  if (refund.status !== 'pending') {
    throw new BadRequestException('Ce remboursement a déjà été traité');
  }

  try {
    // Appel à l'API Stripe
    const stripeRefund = await this.stripeService.createRefund({
      paymentIntentId: refund.order.payment.stripePaymentIntentId,
      amount: Math.round(refund.amount * 100), // Stripe utilise les centimes
      reason: 'requested_by_customer'
    });

    // Mise à jour du remboursement
    refund.status = 'completed';
    refund.transactionId = stripeRefund.id;
    refund.processedAt = new Date();
    refund.adminNote = adminNote;

    await this.refundRepository.save(refund);

    // Mise à jour du statut de la commande si remboursement total
    if (refund.amount >= refund.order.payment.amount) {
      await this.orderRepository.update(refund.orderId, {
        status: 'refunded'
      });
    }

    return refund;
  } catch (error) {
    refund.status = 'rejected';
    refund.adminNote = `Échec Stripe: ${error.message}`;
    await this.refundRepository.save(refund);
    throw new InternalServerErrorException('Le remboursement a échoué');
  }
}
```

**Différence Stripe :**
- **Remboursement total** : Annule complètement le PaymentIntent. Le montant remboursé est égal au montant capturé. Le statut du PaymentIntent passe à `refunded`.
- **Remboursement partiel** : Ne rembourse qu'une partie du montant capturé. Le PaymentIntent reste avec le statut `partially_refunded`. On peut effectuer plusieurs remboursements partiels tant que la somme totale ne dépasse pas le montant original.

**Gestion dans l'API :**
