// refund-provider.interface.ts
export interface RefundProvider {
  createRefund(params: RefundParams): Promise<RefundResult>;
  getRefundStatus(refundId: string): Promise<RefundStatus>;
  supportsPartialRefund(): boolean;
  getAvailableBalance(transactionId: string): Promise<number>;
}

export interface RefundParams {
  transactionId: string;      // paymentIntentId (Stripe) ou captureId (PayPal)
  amount: number;              // en dollars
  currency?: string;           // par défaut 'usd'
  reason?: string;
  metadata?: Record<string, any>;
}

export interface RefundResult {
  refundId: string;
  status: 'succeeded' | 'pending' | 'failed';
  amount: number;
  fee?: number;                // Frais de transaction non remboursés
}

// stripe-refund.provider.ts
export class StripeRefundProvider implements RefundProvider {
  constructor(private stripeService: StripeService) {}

  async createRefund(params: RefundParams): Promise<RefundResult> {
    try {
      const refund = await this.stripeService.refunds.create({
        payment_intent: params.transactionId,
        amount: Math.round(params.amount * 100),
        reason: params.reason === 'defective' ? 'requested_by_customer' : 'duplicate'
      });

      return {
        refundId: refund.id,
        status: refund.status === 'succeeded' ? 'succeeded' : 'pending',
        amount: refund.amount / 100,
        fee: 0  // Stripe ne rembourse pas les frais
      };
    } catch (error) {
      throw new RefundException(`Stripe refund failed: ${error.message}`);
    }
  }

  supportsPartialRefund(): boolean { return true; }

  async getAvailableBalance(transactionId: string): Promise<number> {
    const paymentIntent = await this.stripeService.paymentIntents.retrieve(transactionId);
    const amountRefunded = paymentIntent.amount_refunded || 0;
    return (paymentIntent.amount - amountRefunded) / 100;
  }
}

// paypal-refund.provider.ts
export class PayPalRefundProvider implements RefundProvider {
  constructor(private paypalService: PayPalService) {}

  async createRefund(params: RefundParams): Promise<RefundResult> {
    // PayPal nécessite une capture ID (pas un order ID)
    const refund = await this.paypalService.captures.refund(params.transactionId, {
      amount: {
        value: params.amount.toFixed(2),
        currency_code: params.currency || 'USD'
      },
      note: params.reason,
      invoice_id: params.metadata?.invoiceId
    });

    return {
      refundId: refund.id,
      status: refund.status === 'COMPLETED' ? 'succeeded' : 'pending',
      amount: parseFloat(refund.amount.value),
      fee: 0
    };
  }

  supportsPartialRefund(): boolean { return true; }

  async getAvailableBalance(captureId: string): Promise<number> {
    const capture = await this.paypalService.captures.get(captureId);
    const refundedAmount = capture.refunds?.reduce((sum, r) => sum + parseFloat(r.amount.value), 0) || 0;
    return parseFloat(capture.amount.value) - refundedAmount;
  }
}

// refund.service.ts (utilisant le pattern Strategy)
@Injectable()
export class RefundService {
  private providers: Map<string, RefundProvider> = new Map();

  constructor(
    private stripeProvider: StripeRefundProvider,
    private paypalProvider: PayPalRefundProvider
  ) {
    this.providers.set('stripe', stripeProvider);
    this.providers.set('paypal', paypalProvider);
  }

  async processRefund(refundId: string) {
    const refund = await this.refundRepository.findOne({
      where: { id: refundId },
      relations: ['order', 'order.payment']
    });

    const provider = this.providers.get(refund.refundMethod);
    if (!provider) {
      throw new Error(`No provider for method ${refund.refundMethod}`);
    }

    // Vérifier le solde disponible
    const available = await provider.getAvailableBalance(
      refund.order.payment.providerTransactionId
    );

    if (refund.amount > available) {
      throw new BadRequestException(`Montant (${refund.amount}) > solde disponible (${available})`);
    }

    // Créer le remboursement
    const result = await provider.createRefund({
      transactionId: refund.order.payment.providerTransactionId,
      amount: refund.amount,
      reason: refund.reason,
      metadata: { refundId: refund.id, orderId: refund.orderId }
    });

    // Mettre à jour en base
    refund.status = result.status === 'succeeded' ? 'completed' : 'pending';
    refund.transactionId = result.refundId;
    refund.processedAt = new Date();

    return this.refundRepository.save(refund);
  }
}
