// refund.service.spec.ts
describe('RefundService (multi-provider)', () => {
  let service: RefundService;
  let mockPaypalProvider: jest.Mocked<PayPalRefundProvider>;
  let mockStripeProvider: jest.Mocked<StripeRefundProvider>;
  let mockRefundRepository: jest.Mocked<Repository<Refund>>;

  beforeEach(async () => {
    mockPaypalProvider = {
      createRefund: jest.fn(),
      getAvailableBalance: jest.fn(),
      supportsPartialRefund: jest.fn()
    } as any;

    const module = await Test.createTestingModule({
      providers: [
        RefundService,
        { provide: getRepositoryToken(Refund), useValue: mockRefundRepository },
        { provide: PayPalRefundProvider, useValue: mockPaypalProvider },
        { provide: StripeRefundProvider, useValue: mockStripeProvider }
      ]
    }).compile();

    service = module.get(RefundService);
  });

  it('devrait rembourser une commande PayPal avec succès', async () => {
    // Arrange
    const refund = createMockRefund({
      refundMethod: 'paypal',
      amount: 150,
      order: { payment: { providerTransactionId: 'PAY-123' } }
    });

    mockRefundRepository.findOne.mockResolvedValue(refund);
    mockPaypalProvider.getAvailableBalance.mockResolvedValue(150);
    mockPaypalProvider.createRefund.mockResolvedValue({
      refundId: 'REF-456',
      status: 'succeeded',
      amount: 150
    });

    // Act
    const result = await service.processRefund('refund-123');

    // Assert
    expect(mockPaypalProvider.createRefund).toHaveBeenCalledWith({
      transactionId: 'PAY-123',
      amount: 150,
      reason: refund.reason,
      metadata: expect.any(Object)
    });
    expect(result.status).toBe('completed');
    expect(result.transactionId).toBe('REF-456');
  });

  it('devrait échouer si le solde PayPal est insuffisant', async () => {
    const refund = createMockRefund({
      refundMethod: 'paypal',
      amount: 150
    });

    mockPaypalProvider.getAvailableBalance.mockResolvedValue(50);

    await expect(service.processRefund('refund-123')).rejects.toThrow(
      'Montant (150) > solde disponible (50)'
    );

    expect(mockPaypalProvider.createRefund).not.toHaveBeenCalled();
  });

  it('devrait utiliser le bon provider selon refundMethod', async () => {
    // Test avec Stripe
    const stripeRefund = createMockRefund({ refundMethod: 'stripe' });
    mockRefundRepository.findOne.mockResolvedValue(stripeRefund);
    mockStripeProvider.getAvailableBalance.mockResolvedValue(100);

    await service.processRefund('stripe-refund');

    expect(mockStripeProvider.createRefund).toHaveBeenCalled();
    expect(mockPaypalProvider.createRefund).not.toHaveBeenCalled();
  });
});
